	ids := []int{1, 0, -1}
	for _, id := range ids {
		title, err := checkBook(id)
		if err == nil {
			fmt.Println("Found:", title)
		} else if errors.Is(err, ErrBookNotFound) {
			fmt.Println("Book not in catalog")
			// TODO: Add a separate check for ErrBookOverdue here
		} else {
			fmt.Println("Unknown error:", err)
		}
	}
}

package main

import (
	"errors"
	"fmt"
)

type LibraryError struct {
	Code    string
	Message string
}

func (e LibraryError) Error() string {
	return fmt.Sprintf("[%s] %s", e.Code, e.Message)
}

func checkShelf(shelfID int) error {
	if shelfID < 0 || shelfID > 99 {
		return LibraryError{Code: "INVALID_SHELF", Message: fmt.Sprintf("shelf %d is out of range", shelfID)}
	}
	return nil
}

func main() {
	err := checkShelf(200)
	if err != nil {
		fmt.Println("Error:", err)

		var le LibraryError
		if errors.As(err, &le) {
			fmt.Println("Code:", le.Code)
			fmt.Println("Details:", le.Message)
		}
	}
}

